import { motion } from "framer-motion";
import "./StatusBadge.css";

function StatusBadge({
  label = "ACTIVE",
  variant = "info",
  size = "md",
  pulse = false,
  shimmer = false,
}) {
  return (
    <motion.div
      className={`status-badge ${variant} ${size} ${
        pulse ? "pulse" : ""
      } ${shimmer ? "shimmer" : ""}`}
      initial={{ opacity: 0, y: 6 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
    >
      <span className="badge-dot" />
      <span className="badge-label">{label}</span>
    </motion.div>
  );
}

export default StatusBadge;

.status-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  border-radius: 999px;
  padding: 6px 14px;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.5px;
  text-transform: uppercase;
  position: relative;
  backdrop-filter: blur(8px);
  border: 1px solid rgba(255,255,255,0.08);
  background: rgba(20,25,30,0.8);
  color: #e6edf3;
  overflow: hidden;
}

/* Sizes */

.status-badge.sm {
  font-size: 10px;
  padding: 4px 10px;
}

.status-badge.lg {
  font-size: 14px;
  padding: 8px 18px;
}

/* Dot */

.badge-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: currentColor;
}

/* Variants */

.status-badge.info {
  color: #3d8bff;
  box-shadow: 0 0 10px rgba(61,139,255,0.25);
}

.status-badge.safe {
  color: #2a8f55;
  box-shadow: 0 0 10px rgba(42,143,85,0.25);
}

.status-badge.warning {
  color: #f08a3c;
  box-shadow: 0 0 10px rgba(240,138,60,0.25);
}

.status-badge.critical {
  color: #ff4d4d;
  box-shadow: 0 0 10px rgba(255,77,77,0.3);
}

/* Pulse animation */

.status-badge.pulse .badge-dot {
  animation: pulse 1.8s infinite;
}

@keyframes pulse {
  0% {
    box-shadow: 0 0 0 0 currentColor;
  }
  70% {
    box-shadow: 0 0 0 8px transparent;
  }
  100% {
    box-shadow: 0 0 0 0 transparent;
  }
}

/* Shimmer effect */

.status-badge.shimmer::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(
    120deg,
    transparent,
    rgba(255,255,255,0.15),
    transparent
  );
  transform: translateX(-100%);
  animation: shimmer 2.5s infinite;
}

@keyframes shimmer {
  to {
    transform: translateX(100%);
  }
}
